from anthropic import Anthropic

client = Anthropic()

# Extended thinking via the Anthropic API
# The model generates a hidden thinking block before the response
response = client.messages.create(
    model="claude-opus-4-5",
    max_tokens=16000,
    thinking={
        "type": "enabled",
        "budget_tokens": 10000    # max thinking tokens to spend
    },
    messages=[{
        "role": "user",
        "content": "What is the remainder when 2^1000 is divided by 1000003?"
    }]
)

# The response contains both thinking and text blocks
for block in response.content:
    if block.type == "thinking":
        print(f"Thinking ({len(block.thinking)} chars): {block.thinking[:200]}...")
    elif block.type == "text":
        print(f"Answer: {block.text}")
